#pragma mark - ui事件
- (void)glancePasswordStatusChanged:(UIButton *)glanceButton {
    [glanceButton showClickedAnimation];
    // 改变选中状态
    glanceButton.selected = !glanceButton.isSelected;
    // 拿到输入密码的cell
    AIChatAddCell *passwordCell = [self cellForItemAtIndexPath:[NSIndexPath indexPathForRow:3 inSection:0]];
    passwordCell.textField.secureTextEntry = !glanceButton.isSelected;
}
// 这个是最底部按钮触发的，确认编辑，将编辑的账号密码信息保存到本地
- (void)confirmModify:(UIButton *)sender {
    [sender showClickedAnimationWithLevel:2];
    // 键盘收回
    [self endEditing:YES];
    [UIView showHUDLoading];
    // 判断当前是编辑模式还是新增模式
    AIChatAccountModel *accountToEdit = _account;
    NSInteger ID = 0;   // 智能体ID
    if (!_account) {
        // 新增模式，创建新的账户模型
        accountToEdit = [[AIChatAccountModel alloc] init];
    }
    if (AIChatAccountModel.accounts != nil && [AIChatAccountModel.accounts count] > 0) {
        NSInteger maxID = 0;    // 寻找最大的ID
        for(AIChatAccountModel *account in AIChatAccountModel.accounts) {
            if (account.ID > maxID) {
                maxID = account.ID;
            }
        }
        ID = maxID + 1; // ID递增
    }

    accountToEdit.ID = ID;
    AIChatAddCell *NameCell = [self cellForItemAtIndexPath:[NSIndexPath indexPathForRow:0 inSection:0]];
    AIChatAddCell *IdentityCell=[self cellForItemAtIndexPath:[NSIndexPath indexPathForRow:1 inSection:0]];
    // 确保编辑内容不为无效字符串
    if ((NameCell.textField.text == nil || NameCell.textField.text.isEmpty)) {
        // 弹出“请输入”的hud
        NSString *status = [[NSBundle mainBundle] localizedStringForKey:[NSString stringWithFormat:@"Please enter your name"] value:@"" table:nil];
        [UIView showHUDWithStatus:status imageName:nil];
        return;
    }
    if ((NameCell.textField.text.length>50)) {
        NSString *status = [[NSBundle mainBundle] localizedStringForKey:[NSString stringWithFormat:@"It's too long!"] value:@"" table:nil];
        [UIView showHUDWithStatus:status imageName:nil];
        return;
    }
    NSString *Identity = IdentityCell.textField.text;
    // 检测是否为空消息，纯空格或者纯换行符
    NSString *trimmedString = [Identity stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    if (!([Identity isEqualToString:@""]||[trimmedString length] == 0)) {
        accountToEdit.Identity=[NSString stringWithFormat:@"我希望你以%@的身份回答我", Identity];
    }
    accountToEdit.iconimage=[UIImage imageNamed:@"A_My_image"];
    accountToEdit.IconUrl = self.IconUrl;
    NSURL *url = [NSURL URLWithString:self.IconUrl];//获取地址
    if(url){
        NSURLSession *session = [NSURLSession sharedSession];
        NSURLSessionDataTask *dataTask = [session dataTaskWithURL:url completionHandler:^(NSData *data, NSURLResponse *response, NSError *error) {
            if (error) {
                NSLog(@"Error loading image: %@", error);
                return;
            }
            UIImage *appIcon = [UIImage imageWithData:data];
            if (appIcon) {
                dispatch_async(dispatch_get_main_queue(), ^{
                    accountToEdit.iconimage=appIcon;
                });
            }
        }];
        [dataTask resume];  // 开始任务
    }
    accountToEdit.aiName = NameCell.textField.text;
    if (_account == nil) {
        NameCell.textField.text = nil;
        IdentityCell.textField.text = nil;
    }
    _account.recentChat = @"Click to chat";
    accountToEdit.recentChat = @"Click to chat";
    [AIChatAccountModel save];
    if (_account == nil) {
        NameCell.textField.text = nil;
        IdentityCell.textField.text = nil;
    }
    // 遍历所有添加过的帐号
    __block BOOL accountExist = NO;
    if (!accountExist) {
        // 更新或添加新的账户数据
        if (_account) {
            // 编辑模式，更新已有账户
            NSUInteger indexToUpdate = [AIChatAccountModel.accounts indexOfObject:accountToEdit];
            [AIChatAccountModel.accounts replaceObjectAtIndex:indexToUpdate withObject:accountToEdit];
        } else {
            // 新增模式，添加新的账户
            [AIChatAccountModel.accounts addObject:accountToEdit];
        }
        // 保存新的账户数据
        [AIChatAccountModel save];
    }
    [NSNotificationCenter.defaultCenter postNotificationName:KeePassAccountChangedNotificationName object:nil];
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.5 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
        [SVProgressHUD dismiss];
        // 保存成功，弹出成功的hud
        dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.15 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
            [UIView showHUDWithStatus:NSLocalizedString(@"添加成功", nil) imageName:@"Success"];
            // 账号信息保存执行完毕后，返回上一页
            [self.viewController dismissViewControllerAnimated:YES completion:nil];
            // 如果是editAccount的界面还需要把界面pop掉
            if (self.account != nil) {
                [sender showClickedAnimationWithLevel:2];
                [self.viewController dismissViewControllerAnimated:YES completion:nil];
            }
        });
    });
}

