                    NSURL *linkURL = [NSURL URLWithString:encodedLinkURLString];

                    if (linkURL) {
                        [attributedText addAttribute:NSLinkAttributeName value:linkURL range:absolutePrefixRange];
                    }

                    NSRange contentRange = NSMakeRange(NSMaxRange(absolutePrefixRange), line.length - prefixRange.length);
                    [attributedText addAttribute:NSForegroundColorAttributeName value:BLACK_COLOR range:contentRange];
                    [attributedText addAttribute:NSFontAttributeName value:font range:contentRange];
                }
