            }];
        } else {
            self.messageLabel.hidden = NO;
        }
    }

    // 设置消息文本和时间标签
    self.messageLabel.text = message.text;
    self.timeLabel.text = [NSDateFormatter localizedStringFromDate:message.time dateStyle:NSDateFormatterShortStyle timeStyle:NSDateFormatterShortStyle];
