- (BOOL)textView:(UITextView *)textView shouldInteractWithURL:(NSURL *)URL inRange:(NSRange)characterRange interaction:(UITextItemInteraction)interaction {
    if ([URL.absoluteString hasPrefix:@"customLink://"]) {
        // 提取并发送内容
        NSString *encodedContent = [URL.absoluteString substringFromIndex:@"customLink://".length];
        NSString *content = [encodedContent stringByRemovingPercentEncoding];
        [[NSNotificationCenter defaultCenter] postNotificationName:@"AIChatTopicMessageSent" object:content ];
        return NO; // 禁止系统默认的超链接行为
    }
    return YES;
}



