- (void)setAccount:(AIChatAccountModel *)account {
    _account = account;
    if(account.IconUrl==nil){
        account.iconimage = [UIImage imageNamed:@"A_icon"];
    }
    else{
        NSURL *iconUrl = [NSURL URLWithString:account.IconUrl];
        // 使用 NSURLSession 异步加载图片
        NSURLSession *session = [NSURLSession sharedSession];
        NSURLSessionDataTask *dataTask = [session dataTaskWithURL:iconUrl completionHandler:^(NSData *data, NSURLResponse *response, NSError *error) {
            if (error) {
                NSLog(@"Error loading image: %@", error);
                return;
            }
            UIImage *appIcon = [UIImage imageWithData:data];
            if (appIcon) {
                // 在主线程更新 UI
                dispatch_async(dispatch_get_main_queue(), ^{
                    account.iconimage = appIcon;
                    self.iconImageView.image = account.iconimage; //这里需要是self，否则报警告
                });
            }
        }];
        [dataTask resume];  // 开始任务
    }
    _nameLabel.text = account.aiName;
    _talkLabel.text = account.recentChat.length ? account.recentChat : @"";
    _dateLabel.text = [self latestTimeTextForAccount:account];
}
