- (NSString *)latestTimeTextForAccount:(AIChatAccountModel *)account {
    AIChatMessageModel *lastMessage = [AIChatMessageModel messagesForAccount:account.ID].lastObject;
    if (!lastMessage.time) {
        return @"";
    }
    NSDateFormatter *formatter = [[NSDateFormatter alloc] init];
    if ([[NSCalendar currentCalendar] isDateInToday:lastMessage.time]) {
        formatter.dateFormat = @"HH-mm";
    } else {
        formatter.dateFormat = @"MM-dd";
    }
    return [formatter stringFromDate:lastMessage.time];
}

