#import "PlayView.h"
#import "AudioManager.h"

@interface PlayView ()

@property (nonatomic, strong) UIScrollView *scrollView;
@property (nonatomic, strong) NSArray<NSDictionary *> *modes;
@property (nonatomic, strong) NSMutableArray<UIButton *> *cardButtons;
@property (nonatomic, strong) NSMutableArray<UIImageView *> *overlayViews;
@property (nonatomic, assign) NSInteger currentModeIndex;
@property (nonatomic, assign) BOOL isPlaying;

@end

@implementation PlayView

- (instancetype)init {
    self = [super init];
    if (self) {
        _currentModeIndex = 0;
        _isPlaying = NO;
        _modes = @[
            @{@"title": @"The sound of falling snow", @"file": @"踩雪声.mp3", @"image": @"A_Sonwpic"},
            @{@"title": @"Quiet night", @"file": @"夜间.mp3", @"image": @"A_Nightpic"},
            @{@"title": @"Surging waves", @"file": @"海浪声.mp3", @"image": @"A_Wavepic"}
        ];
        _cardButtons = [NSMutableArray array];
        _overlayViews = [NSMutableArray array];
        [self setUpUI];
    }
    return self;
}

- (void)setUpUI {
    self.backgroundColor = WHITE_COLOR;
    [self addSubview:self.scrollView];
    [self.scrollView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(self);
    }];

    UIView *previousView = nil;
    for (NSInteger i = 0; i < self.modes.count; i++) {
        NSDictionary *mode = self.modes[i];

        UIView *container = [[UIView alloc] init];
        container.backgroundColor = CLEAR_COLOR;
        [self.scrollView addSubview:container];

        UIButton *cardButton = [UIButton buttonWithType:UIButtonTypeCustom];
        cardButton.tag = i;
        cardButton.layer.cornerRadius = ZOOM(12);
        cardButton.layer.masksToBounds = YES;
        [cardButton setBackgroundImage:[UIImage imageNamed:mode[@"image"]] forState:UIControlStateNormal];
        [cardButton addTarget:self action:@selector(cardTapped:) forControlEvents:UIControlEventTouchUpInside];
        [container addSubview:cardButton];
        [self.cardButtons addObject:cardButton];

        UIImageView *overlayView = [[UIImageView alloc] initWithImage:[UIImage imageNamed:@"A_Selectedplay"]];
        overlayView.contentMode = UIViewContentModeScaleAspectFit;
        [container addSubview:overlayView];
        [self.overlayViews addObject:overlayView];

        UILabel *titleLabel = [[UILabel alloc] init];
        titleLabel.text = mode[@"title"];
        titleLabel.textColor = RGBA(95, 95, 95, 1);
        titleLabel.font = [UIFont systemFontOfSize:15 weight:UIFontWeightSemibold];
        titleLabel.textAlignment = NSTextAlignmentCenter;
        [container addSubview:titleLabel];

        [container mas_makeConstraints:^(MASConstraintMaker *make) {
            make.left.right.equalTo(self.scrollView);
            make.width.equalTo(self.scrollView);
            if (previousView) {
                make.top.equalTo(previousView.mas_bottom).offset(ZOOM(18));
            } else {
                make.top.equalTo(self.scrollView).offset(ZOOM(16));
            }
            if (i == self.modes.count - 1) {
                make.bottom.equalTo(self.scrollView).offset(ZOOM(-20));
            }
        }];

        [cardButton mas_makeConstraints:^(MASConstraintMaker *make) {
            make.top.equalTo(container);
            make.left.right.equalTo(container).inset(ZOOMW(14));
            make.height.mas_equalTo(ZOOM(134));
        }];

        [overlayView mas_makeConstraints:^(MASConstraintMaker *make) {
            make.center.equalTo(cardButton);
            make.width.height.mas_equalTo(ZOOM(48));
        }];

        [titleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
            make.top.equalTo(cardButton.mas_bottom).offset(ZOOM(10));
            make.left.right.equalTo(container).inset(ZOOMW(20));
            make.bottom.equalTo(container);
        }];

        previousView = container;
    }

    [self updateOverlayStates];
}

- (void)cardTapped:(UIButton *)sender {
    NSInteger index = sender.tag;
    if (self.currentModeIndex == index) {
        [self togglePlayPause];
        return;
    }

    if (self.isPlaying) {
        [[AudioManager sharedInstance] toggleBackgroundMusicWithtitle:self.modes[self.currentModeIndex][@"file"]];
        self.isPlaying = NO;
    }
    self.currentModeIndex = index;
    if ([self.delegate respondsToSelector:@selector(playViewRequestStartPlayback:)]) {
        [self.delegate playViewRequestStartPlayback:self];
    } else {
        [self startPlaybackForCurrentMode];
    }
}

- (void)togglePlayPause {
    if ([self.delegate respondsToSelector:@selector(playViewRequestStartPlayback:)] && !self.isPlaying) {
        [self.delegate playViewRequestStartPlayback:self];
        return;
    }
    [[AudioManager sharedInstance] toggleBackgroundMusicWithtitle:self.modes[self.currentModeIndex][@"file"]];
    self.isPlaying = !self.isPlaying;
    [self updateOverlayStates];
}

- (void)playNextMode {
    if (self.isPlaying) {
        [[AudioManager sharedInstance] toggleBackgroundMusicWithtitle:self.modes[self.currentModeIndex][@"file"]];
        self.isPlaying = NO;
    }
    self.currentModeIndex = (self.currentModeIndex + 1) % self.modes.count;
    if ([self.delegate respondsToSelector:@selector(playViewRequestStartPlayback:)]) {
        [self.delegate playViewRequestStartPlayback:self];
    } else {
        [self startPlaybackForCurrentMode];
    }
}

- (void)startPlaybackForCurrentMode {
    NSString *fileName = self.modes[self.currentModeIndex][@"file"];
    [[AudioManager sharedInstance] toggleBackgroundMusicWithtitle:fileName];
    self.isPlaying = YES;
    [self updateOverlayStates];
}

- (void)updateOverlayStates {
    for (NSInteger i = 0; i < self.overlayViews.count; i++) {
        UIImageView *overlayView = self.overlayViews[i];
        BOOL isCurrent = (i == self.currentModeIndex);
        NSString *imageName = (isCurrent && self.isPlaying) ? @"A_Selectedpause" : @"A_Selectedplay";
        overlayView.image = [UIImage imageNamed:imageName];
        overlayView.alpha = isCurrent ? 1.0 : 0.96;
    }
}

- (UIScrollView *)scrollView {
    if (!_scrollView) {
        _scrollView = [[UIScrollView alloc] init];
        _scrollView.backgroundColor = WHITE_COLOR;
        _scrollView.showsVerticalScrollIndicator = NO;
    }
    return _scrollView;
}

@end

