    self.contentView.backgroundColor = CLEAR_COLOR;
    self.selectedBackgroundView = [[UIView alloc] init];
    self.selectedBackgroundView.backgroundColor = CLEAR_COLOR;
    self.separatorView = [[UIView alloc] initWithFrame:CGRectZero];
    self.separatorView.backgroundColor = CLEAR_COLOR;
    [self addAllSubviews];
    [self addAllConstraints];
}
- (void)addAllSubviews {
    [self.contentView addSubview:self.cardView];
    [self.cardView addSubview:self.nameLabel];
    [self.cardView addSubview:self.dateLabel];
    [self.cardView addSubview:self.talkLabel];
    [self.contentView addSubview:self.separatorView];
}
- (void)addAllConstraints {
    [self.cardView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.contentView).offset(ZOOM(4));
        make.bottom.equalTo(self.contentView).offset(ZOOM(-4));
        make.left.right.equalTo(self.contentView).inset(ZOOMW(8));
    }];
    [_nameLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.cardView).offset(ZOOM(12));
        make.left.equalTo(self.cardView).offset(ZOOMW(12));
        make.right.lessThanOrEqualTo(self.dateLabel.mas_left).offset(ZOOMW(-10));
        make.height.mas_greaterThanOrEqualTo(ZOOM(18));
    }];
    [_dateLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(self.nameLabel);
        make.right.equalTo(self.cardView).offset(ZOOMW(-12));
        make.left.greaterThanOrEqualTo(self.nameLabel.mas_right).offset(ZOOMW(10));
    }];
    [_talkLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.nameLabel.mas_bottom).offset(ZOOM(6));
        make.left.equalTo(self.nameLabel);
        make.right.equalTo(self.cardView).offset(ZOOMW(-12));
        make.bottom.equalTo(self.cardView).offset(ZOOM(-12));
    }];

    [self.separatorView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.contentView).offset(ZOOMW(16));
        make.right.equalTo(self.contentView);
        make.bottom.equalTo(self.contentView);
        make.height.mas_equalTo(0);
    }];

}

- (NSString *)latestTimeTextForAccount:(AIChatAccountModel *)account {
    AIChatMessageModel *lastMessage = [AIChatMessageModel messagesForAccount:account.ID].lastObject;
    if (!lastMessage.time) {
        return @"";
    }
    NSDateFormatter *formatter = [[NSDateFormatter alloc] init];
    if ([[NSCalendar currentCalendar] isDateInToday:lastMessage.time]) {
        formatter.dateFormat = @"HH:mm";
    } else {
        formatter.dateFormat = @"MM-dd";
    }
    return [formatter stringFromDate:lastMessage.time];
}

