- (UIImageView *)iconImageView {
    if (_iconImageView == nil) {

        CGFloat iconW = ZOOM(54);
        // 设置张初始图片
        UIImageView *iconImageView = [[UIImageView alloc] initWithImage:[UIImage imageNamed:@"A_icon"]];
        iconImageView.layer.cornerRadius = ZOOM(8);
        iconImageView.layer.masksToBounds = YES;

        [iconImageView mas_makeConstraints:^(MASConstraintMaker *make) {
            make.width.height.mas_equalTo(iconW);
        }];
        _iconImageView = iconImageView;
        _iconImageView.hidden = YES;
    }
    return _iconImageView;
}

- (UILabel *)nameLabel {
    if (_nameLabel == nil) {
        UILabel *nameLabel = [UILabel labelWithText:nil fontSize:16 bold:YES textColor:RGB(51, 51, 51)];
        nameLabel.font = [UIFont systemFontOfSize:15 weight:UIFontWeightSemibold];
        _nameLabel = nameLabel;
        _nameLabel.textAlignment = NSTextAlignmentLeft;
    }
