}

- (UILabel *)dateLabel {
    if (_dateLabel == nil) {
        UILabel *dateLabel = [UILabel labelWithText:@"" fontSize:12 bold:NO textColor:RGBA(153, 153, 153, 1)];
        dateLabel.font = [UIFont systemFontOfSize:11 weight:UIFontWeightRegular];
        _dateLabel = dateLabel;
        _dateLabel.textAlignment = NSTextAlignmentRight;
    }
    return _dateLabel;
}

- (UILabel *)talkLabel {
    if (_talkLabel == nil) {
        UILabel *talkLabel = [UILabel labelWithText:@"" fontSize:14 bold:NO textColor:RGBA(102, 102, 102, 1)];
        talkLabel.font = [UIFont systemFontOfSize:13 weight:UIFontWeightRegular];
        _talkLabel = talkLabel;
        _talkLabel.textAlignment = NSTextAlignmentLeft;
        _talkLabel.lineBreakMode = NSLineBreakByTruncatingTail;
    }
    return _talkLabel;
}

