#import "SpecialSymbolsView.h"
#import <Masonry/Masonry.h>

@interface SpecialSymbolsView ()
@property (nonatomic, strong) UILabel *titleLabel;
@property (nonatomic, strong) UIView *buttonsContainer;
@property (nonatomic, strong) NSArray<UIButton *> *symbolButtons;
@property (nonatomic, strong) NSArray<NSString *> *symbols;
@property (nonatomic, strong) NSMutableArray<NSString *> *selectedSymbols;
@end

@implementation SpecialSymbolsView

- (instancetype)init {
    self = [super init];
    if (self) {
        _symbols = @[@"#", @"$", @"%", @"&", @"*", @"@"];
        _selectedSymbols = [NSMutableArray array];
        [self setupUI];
    }
    return self;
}

- (void)setupUI {
    self.backgroundColor = CLEAR_COLOR;

    [self addSubview:self.titleLabel];
    [self addSubview:self.buttonsContainer];

    [self setupConstraints];
    [self createSymbolButtons];
}

- (void)setupConstraints {
    [self.titleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.left.equalTo(self);
        make.centerX.equalTo(self);
    }];

    [self.buttonsContainer mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.right.bottom.equalTo(self);
        make.height.mas_equalTo(ZOOMW(48));
    }];
}

- (void)createSymbolButtons {
    NSMutableArray *buttons = [NSMutableArray array];

    for (int i = 0; i < self.symbols.count; i++) {
        UIButton *button = [UIButton buttonWithType:UIButtonTypeCustom];
        [button setBackgroundImage:[UIImage imageNamed:[@"A_" stringByAppendingString:self.symbols[i]]] forState:UIControlStateNormal];
        [button setBackgroundImage:[UIImage imageNamed:[@"A_select_" stringByAppendingString:self.symbols[i]]] forState:UIControlStateSelected];
        button.titleLabel.font = [UIFont systemFontOfSize:20 weight:UIFontWeightMedium];
        button.layer.cornerRadius = ZOOMW(16);
        button.layer.masksToBounds = YES;
        button.tag = i;

        [button addTarget:self action:@selector(symbolButtonTapped:) forControlEvents:UIControlEventTouchUpInside];

        [self.buttonsContainer addSubview:button];
        [buttons addObject:button];
    }

    self.symbolButtons = [buttons copy];
    [self layoutSymbolButtons];
}

- (void)layoutSymbolButtons {
    if (self.symbolButtons.count == 0) return;

    UIButton *firstButton = self.symbolButtons.firstObject;
    [firstButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.buttonsContainer);
        make.centerY.equalTo(self.buttonsContainer);
        make.width.height.mas_equalTo(ZOOMW(48));
    }];

    for (int i = 1; i < self.symbolButtons.count; i++) {
        UIButton *previousButton = self.symbolButtons[i-1];
        UIButton *currentButton = self.symbolButtons[i];

        [currentButton mas_makeConstraints:^(MASConstraintMaker *make) {
            make.left.equalTo(previousButton.mas_right).offset(ZOOMW(12));
            make.centerY.equalTo(self.buttonsContainer);
            make.width.height.mas_equalTo(ZOOMW(48));
            if (i == self.symbolButtons.count - 1) {
                make.right.equalTo(self.buttonsContainer);
            }
        }];
    }
}

#pragma mark - Lazy Loading

- (UILabel *)titleLabel {
    if (!_titleLabel) {
        _titleLabel = [[UILabel alloc] init];
        _titleLabel.text = @"特殊符号";
        _titleLabel.textColor = [UIColor blackColor];
        _titleLabel.font = [UIFont systemFontOfSize:16 weight:UIFontWeightMedium];
    }
    return _titleLabel;
}

- (UIView *)buttonsContainer {
    if (!_buttonsContainer) {
        _buttonsContainer = [[UIView alloc] init];
        _buttonsContainer.backgroundColor = [UIColor clearColor];
    }
    return _buttonsContainer;
}

#pragma mark - Button Actions

- (void)symbolButtonTapped:(UIButton *)sender {
    NSString *symbol = self.symbols[sender.tag];

    // 切换选中状态
    sender.selected = !sender.selected;

    if (sender.selected) {
        // 添加到选中数组
        if (![self.selectedSymbols containsObject:symbol]) {
            [self.selectedSymbols addObject:symbol];
        }
    } else {
        // 从选中数组中移除
        [self.selectedSymbols removeObject:symbol];
    }

    // 更新按钮背景颜色
    sender.backgroundColor = sender.selected ? RGBA(240, 240, 240, 1) : [UIColor whiteColor];

    // 回调
    if (self.onSymbolsSelected) {
        self.onSymbolsSelected([self.selectedSymbols copy]);
    }
}

#pragma mark - Public Methods

- (NSArray<NSString *> *)getSelectedSymbols {
    return [self.selectedSymbols copy];
}

- (void)setSelectedSymbols:(NSArray<NSString *> *)symbols {
    [self.selectedSymbols removeAllObjects];

    for (NSString *symbol in symbols) {
        NSInteger index = [self.symbols indexOfObject:symbol];
        if (index != NSNotFound && index < self.symbolButtons.count) {
            UIButton *button = self.symbolButtons[index];
            button.selected = YES;
            button.backgroundColor = RGBA(240, 240, 240, 1);
            [self.selectedSymbols addObject:symbol];
        }
    }

    if (self.onSymbolsSelected) {
        self.onSymbolsSelected([self.selectedSymbols copy]);
    }
}

- (void)clearSelection {
    for (UIButton *button in self.symbolButtons) {
        button.selected = NO;
        button.backgroundColor = [UIColor whiteColor];
    }
    [self.selectedSymbols removeAllObjects];

    if (self.onSymbolsSelected) {
        self.onSymbolsSelected(@[]);
    }
}

- (void)selectAllSymbols {
    for (int i = 0; i < self.symbolButtons.count; i++) {
        UIButton *button = self.symbolButtons[i];
        button.selected = YES;
        button.backgroundColor = RGBA(240, 240, 240, 1);

        NSString *symbol = self.symbols[i];
        if (![self.selectedSymbols containsObject:symbol]) {
            [self.selectedSymbols addObject:symbol];
        }
    }

    if (self.onSymbolsSelected) {
        self.onSymbolsSelected([self.selectedSymbols copy]);
    }
}

@end

