- (void)confirmModify:(UIButton *)sender {
    [sender showClickedAnimationWithLevel:2];
    [self endEditing:YES];
    [UIView showHUDLoading];

    AIChatAccountModel *accountToEdit = self.account ?: [[AIChatAccountModel alloc] init];
    NSInteger ID = 0;
    if (AIChatAccountModel.accounts.count > 0) {
        NSInteger maxID = 0;
        for (AIChatAccountModel *account in AIChatAccountModel.accounts) {
            if (account.ID > maxID) {
                maxID = account.ID;
            }
        }
        ID = maxID + 1;
    }

    AIChatAddCell *nameCell = (AIChatAddCell *)[self cellForItemAtIndexPath:[NSIndexPath indexPathForRow:0 inSection:0]];
    NSString *name = [nameCell.textField.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    if (name.isEmpty) {
        NSString *status = [[NSBundle mainBundle] localizedStringForKey:@"Please enter your name" value:@"" table:nil];
        [UIView showHUDWithStatus:status imageName:nil];
        return;
    }
    if (name.length > 50) {
        NSString *status = [[NSBundle mainBundle] localizedStringForKey:@"It's too long!" value:@"" table:nil];
        [UIView showHUDWithStatus:status imageName:nil];
        return;
    }

    accountToEdit.ID = self.account ? self.account.ID : ID;
    accountToEdit.aiName = name;
    accountToEdit.Identity = nil;
    accountToEdit.iconimage = [UIImage imageNamed:@"A_My_image"];
    accountToEdit.IconUrl = self.IconUrl;
    accountToEdit.recentChat = @"Click to chat";

    NSURL *url = [NSURL URLWithString:self.IconUrl];
    if (url) {
        NSURLSessionDataTask *dataTask = [NSURLSession.sharedSession dataTaskWithURL:url completionHandler:^(NSData *data, NSURLResponse *response, NSError *error) {
            if (error) {
                NSLog(@"Error loading image: %@", error);
                return;
            }
            UIImage *appIcon = [UIImage imageWithData:data];
            if (appIcon) {
                dispatch_async(dispatch_get_main_queue(), ^{
                    accountToEdit.iconimage = appIcon;
                });
            }
        }];
        [dataTask resume];
    }

    if (self.account) {
        NSUInteger indexToUpdate = [AIChatAccountModel.accounts indexOfObject:self.account];
        if (indexToUpdate != NSNotFound) {
            [AIChatAccountModel.accounts replaceObjectAtIndex:indexToUpdate withObject:accountToEdit];
        }
    } else {
        [AIChatAccountModel.accounts addObject:accountToEdit];
        nameCell.textField.text = nil;
    }
    [AIChatAccountModel save];

    [NSNotificationCenter.defaultCenter postNotificationName:KeePassAccountChangedNotificationName object:nil];
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.5 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
        [SVProgressHUD dismiss];
        dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.15 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
            [UIView showHUDWithStatus:NSLocalizedString(@"添加成功", nil) imageName:@"Success"];
            [self.viewController dismissViewControllerAnimated:YES completion:nil];
        });
    });
}

