- (IBAction)showScrollingText:(id)sender {
    // 收集用户输入的数据
    NSString *text = self.text.text;
    NSString *sizeStr = self.size.text;
    NSString *speedStr = self.speed.text;
    UIColor *textColor = self.textColor.backgroundColor;
    UIColor *backgroundColor = self.backgroundColor.backgroundColor;

    // 检查 size 是否为数字
    BOOL isSizeValid = YES;
    for (NSInteger i = 0; i < sizeStr.length; i++) {
        unichar character = [sizeStr characterAtIndex:i];
        if (!isdigit(character)) {
            isSizeValid = NO;
            break;
        }
    }

    // 检查 speed 是否为数字
    BOOL isSpeedValid = YES;
    for (NSInteger i = 0; i < speedStr.length; i++) {
        unichar character = [speedStr characterAtIndex:i];
        if (!isdigit(character)) {
            isSpeedValid = NO;
            break;
        }
    }

    // 如果 size 不是数字或者不在合理范围内 (100 到 300)
    if (!isSizeValid || [sizeStr doubleValue] > 300.0 || [sizeStr doubleValue] < 100.0) {
        UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"警告" message:@"请输入正确的文字大小（100 到 300）" preferredStyle:UIAlertControllerStyleAlert];
            UIAlertAction *okAction = [UIAlertAction actionWithTitle:@"确定" style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
                // 用户点击确定后重置输入框
                self.size.text = @"";
            }];
            [alert addAction:okAction];
            [self presentViewController:alert animated:YES completion:nil];
            return;
        }

    // 如果 speed 不是数字或者不在合理范围内 (0 到 10)
    if (!isSpeedValid || [speedStr doubleValue] > 10.0 || [speedStr doubleValue] < 0.0) {
        UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"警告" message:@"请输入正确的滚动速度（0 到 10）" preferredStyle:UIAlertControllerStyleAlert];
        UIAlertAction *okAction = [UIAlertAction actionWithTitle:@"确定" style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
            // 用户点击确定后重置输入框
            self.speed.text = @"";
        }];
        [alert addAction:okAction];
        [self presentViewController:alert animated:YES completion:nil];
        return;
    }

    // 将字符串转换为数值
    CGFloat size = [sizeStr doubleValue];
    CGFloat speed = [speedStr doubleValue];

    // 实例化滚动字幕视图控制器
    ScrollingTextViewController *scrollingVC = [[ScrollingTextViewController alloc] init];
    scrollingVC.text = text;
    scrollingVC.size = size;
    scrollingVC.scrollSpeed = speed;
    scrollingVC.textColor = textColor;
    scrollingVC.backgroundColor = backgroundColor;
    scrollingVC.isLandscapeEnabled = self.isLandscapeEnabled; // 传递横屏/竖屏模式
    scrollingVC.isScrollingEnabled = self.isScrollingEnabled;    // 传递静态/滚动模式

    // 将滚动字幕视图控制器显示出来
    scrollingVC.modalPresentationStyle = UIModalPresentationOverFullScreen;
    [self presentViewController:scrollingVC animated:YES completion:nil];
}

